#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/types.h>
#include <sys/ipc.h>
#include <sys/msg.h>

// Message structure
struct msgbuf {
 long mtype; // Message type (must be > 0)
 char mtext[100]; // Message data
};

int main() {
 key_t key = ftok("/tmp", 'M'); // Generate unique key
 int msgid;
 struct msgbuf message;

 // Create message queue with IPC_CREAT | 0666 permissions
 msgid = msgget(key, IPC_CREAT | 0666);
 if (msgid == -1) {
 perror("msgget failed");
 exit(1);
 }

 // Send message
 message.mtype = 1; // Message type 1
 strcpy(message.mtext, "Hello from Producer");
 if (msgsnd(msgid, &message, sizeof(message.mtext), 0) == -1) {
 perror("msgsnd failed");
 exit(1);
 }

 // Receive message
 if (msgrcv(msgid, &message, sizeof(message.mtext), 1, 0) == -1) {
 perror("msgrcv failed");
 exit(1);
 }
 printf("Received: %s\n", message.mtext);

 // Remove message queue
 if (msgctl(msgid, IPC_RMID, NULL) == -1) {
 perror("msgctl failed");
 exit(1);
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <unistd.h>

#define QUEUE_NAME "/test_queue"
#define MAX_MSG 10
#define MAX_MSG_SIZE 256

int main() {
 mqd_t mq;
 struct mq_attr attr;
 char buffer[MAX_MSG_SIZE];

 // Set queue attributes
 attr.mq_flags = 0;
 attr.mq_maxmsg = MAX_MSG;
 attr.mq_msgsize = MAX_MSG_SIZE;
 attr.mq_curmsgs = 0;

 // Create/open message queue
 mq = mq_open(QUEUE_NAME, O_CREAT | O_WRONLY, 0644, &attr);
 if (mq == (mqd_t)-1) {
 perror("mq_open failed");
 exit(1);
 }

 // Send messages
 for (int i = 1; i <= 5; i++) {
 sprintf(buffer, "Message %d from producer", i);
 if (mq_send(mq, buffer, strlen(buffer) + 1, i) == -1) {
 perror("mq_send failed");
 exit(1);
 }
 printf("Sent: %s (priority: %d)\n", buffer, i);
 }

 mq_close(mq);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>
#include <unistd.h>

#define QUEUE_NAME "/test_queue"
#define MAX_MSG_SIZE 256

int main() {
 mqd_t mq;
 struct mq_attr attr;
 char buffer[MAX_MSG_SIZE];
 ssize_t bytes_read;
 unsigned int priority;

 // Open existing queue (read-only)
 mq = mq_open(QUEUE_NAME, O_RDONLY);
 if (mq == (mqd_t)-1) {
 perror("mq_open failed");
 exit(1);
 }

 // Get queue attributes
 mq_getattr(mq, &attr);
 printf("Queue max messages: %ld\n", attr.mq_maxmsg);
 printf("Queue max size: %ld\n", attr.mq_msgsize);

 // Receive messages (loop until queue empty)
 while (1) {
 bytes_read = mq_receive(mq, buffer, attr.mq_msgsize, &priority);
 if (bytes_read == -1) {
 perror("mq_receive failed");
 break;
 }
 printf("Received: %s (priority: %u, bytes: %zd)\n", 
 buffer, priority, bytes_read);
 }

 mq_close(mq);
 // Use mq_unlink(QUEUE_NAME) to remove queue
 return 0;
}

#include <stdio.h>
#define MAX_SIZE 10

typedef struct {
 int data[MAX_SIZE];
 int front; // Points to first element
 int rear; // Points to next empty slot
 int size;
} CircularQueue;

void initQueue(CircularQueue *q) {
 q->front = -1;
 q->rear = -1;
 q->size = 0;
}

int isFull(CircularQueue *q) {
 return q->size == MAX_SIZE;
}

int isEmpty(CircularQueue *q) {
 return q->size == 0;
}

int enqueue(CircularQueue *q, int value) {
 if (isFull(q)) {
 printf("Queue is full!\n");
 return -1;
 }
 // Wrap rear using modulo
 q->rear = (q->rear + 1) % MAX_SIZE;
 q->data[q->rear] = value;
 q->size++;
 if (q->front == -1) q->front = 0;
 return 0;
}

int dequeue(CircularQueue *q, int *value) {
 if (isEmpty(q)) {
 printf("Queue is empty!\n");
 return -1;
 }
 *value = q->data[q->front];
 // Wrap front using modulo
 q->front = (q->front + 1) % MAX_SIZE;
 q->size--;
 if (q->size == 0) {
 q->front = -1;
 q->rear = -1;
 }
 return 0;
}

int main() {
 CircularQueue q;
 initQueue(&q);

 // Add 5 elements
 for (int i = 1; i <= 5; i++) enqueue(&q, i * 10);

 // Remove 2, add 2 more (demonstrates wrapping)
 int val;
 dequeue(&q, &val); dequeue(&q, &val);
 enqueue(&q, 70); enqueue(&q, 80);

 printf("Queue size: %d\n", q.size);
 return 0;
}

#include <stdio.h>
#include <stdlib.h>

typedef struct {
 int data;
 int priority;
} Message;

typedef struct {
 Message *messages;
 int size;
 int capacity;
} PriorityQueue;

void initPQ(PriorityQueue *pq, int capacity) {
 pq->capacity = capacity;
 pq->size = 0;
 pq->messages = malloc(capacity * sizeof(Message));
}

void insert(PriorityQueue *pq, int data, int priority) {
 if (pq->size >= pq->capacity) {
 printf("Priority Queue full!\n");
 return;
 }
 // Add at end
 pq->messages[pq->size].data = data;
 pq->messages[pq->size].priority = priority;
 pq->size++;

 // Bubble up to maintain heap property (max priority first)
 int i = pq->size - 1;
 while (i > 0) {
 int parent = (i - 1) / 2;
 if (pq->messages[parent].priority >= pq->messages[i].priority)
 break;
 // Swap
 Message temp = pq->messages[i];
 pq->messages[i] = pq->messages[parent];
 pq->messages[parent] = temp;
 i = parent;
 }
}

int extractMax(PriorityQueue *pq, Message *msg) {
 if (pq->size == 0) return -1;

 *msg = pq->messages[0]; // Get highest priority
 pq->messages[0] = pq->messages[--pq->size];

 // Bubble down
 int i = 0;
 while (1) {
 int left = 2*i + 1, right = 2*i + 2, largest = i;
 if (left < pq->size && pq->messages[left].priority > pq->messages[largest].priority)
 largest = left;
 if (right < pq->size && pq->messages[right].priority > pq->messages[largest].priority)
 largest = right;
 if (largest == i) break;
 Message temp = pq->messages[i];
 pq->messages[i] = pq->messages[largest];
 pq->messages[largest] = temp;
 i = largest;
 }
 return 0;
}

int main() {
 PriorityQueue pq;
 initPQ(&pq, 10);
 Message msg;

 insert(&pq, 100, 3); // Data=100, Priority=3
 insert(&pq, 200, 1);
 insert(&pq, 300, 5);
 insert(&pq, 400, 2);

 printf("Extracting in priority order:\n");
 while (extractMax(&pq, &msg) == 0)
 printf("Data: %d, Priority: %d\n", msg.data, msg.priority);

 return 0;
}
